    Class<?> helperClass = ReflectionAccessFilterHelper.class;
    Class<?> accessCheckerClass = null;
    for (Class<?> innerClass : helperClass.getDeclaredClasses()) {
      if ("AccessChecker".equals(innerClass.getSimpleName())) {
        accessCheckerClass = innerClass;
        break;
      }
    }
    assertNotNull(accessCheckerClass);

    Field instanceField = accessCheckerClass.getDeclaredField("INSTANCE");
    instanceField.setAccessible(true);

    Object originalInstance = instanceField.get(null);

    Object mockAccessChecker = mock(accessCheckerClass);

    // Setup mock canAccess method to return true
    Method canAccessMethod = accessCheckerClass.getMethod("canAccess", AccessibleObject.class, Object.class);
    when(canAccessMethod.invoke(mockAccessChecker, accessibleObjectMock, targetObject)).thenReturn(true);

    // Replace INSTANCE with mock
    instanceField.set(null, mockAccessChecker);

    boolean result = ReflectionAccessFilterHelper.canAccess(accessibleObjectMock, targetObject);
    assertTrue(result);

    // Verify canAccess was called
    verify(mockAccessChecker).getClass().getMethod("canAccess", AccessibleObject.class, Object.class);

    // Restore original INSTANCE
    instanceField.set(null, originalInstance);
  }

